	private boolean invokeBooleanGetter(Object target, String getterName) {
		try {
			Method getter = target.getClass().getMethod(getterName);
			return (boolean) getter.invoke(target);
		} catch (ReflectiveOperationException e) {
			throw new AssertionError("Missing LMDB codegen boolean getter: " + getterName, e);
		}
	}

	private Throwable rootCauseOf(Throwable throwable) {
		Throwable current = throwable;
		while (current.getCause() != null) {
			current = current.getCause();
		}
		return current;
	}

	private String invokeStringGetter(Object target, String getterName) {
		try {
			Method getter = target.getClass().getMethod(getterName);
			return (String) getter.invoke(target);
		} catch (ReflectiveOperationException e) {
			throw new AssertionError("Missing LMDB codegen string getter: " + getterName, e);
		}
	}

	private List<String> drain(QueryEvaluationStep evaluationStep, BindingSet bindings) {
		List<String> rows = new ArrayList<>();
		try (CloseableIteration<BindingSet> iteration = evaluationStep.evaluate(bindings)) {
			while (iteration.hasNext()) {
				BindingSet row = iteration.next();
				rows.add(render(row));
			}
		}
		return rows;
	}

	private List<String> drainGeneric(QueryEvaluationStep evaluationStep, BindingSet bindings) {
		List<String> rows = new ArrayList<>();
		try (CloseableIteration<BindingSet> iteration = evaluationStep.evaluate(bindings)) {
			while (iteration.hasNext()) {
				rows.add(renderBindingSet(iteration.next()));
			}
		}
		return rows;
	}

	private String render(BindingSet row) {
		return row.getValue("a").stringValue() + "|" + row.getValue("b").stringValue() + "|"
				+ row.getValue("c").stringValue();
	}

	private String renderBindingSet(BindingSet row) {
		List<String> bindingNames = new ArrayList<>(row.getBindingNames());
		bindingNames.sort(String::compareTo);
		StringBuilder builder = new StringBuilder();
		for (int i = 0; i < bindingNames.size(); i++) {
			if (i > 0) {
				builder.append('|');
			}
			String bindingName = bindingNames.get(i);
			builder.append(bindingName).append('=').append(row.getValue(bindingName).stringValue());
		}
		return builder.toString();
	}

	private void assertPatchedSeekBuffer(long prefixValue, long firstTarget, long secondTarget) {
		ByteBuffer keyBuffer = ByteBuffer.allocate(TripleStore.MAX_KEY_LENGTH);
		Varint.writeUnsigned(keyBuffer, prefixValue);
		int prefixLength = keyBuffer.position();

		patchSeekTail(keyBuffer, prefixLength, firstTarget);
		assertThat(readPatchedPair(keyBuffer)).containsExactly(prefixValue, firstTarget);

		patchSeekTail(keyBuffer, prefixLength, secondTarget);
		assertThat(readPatchedPair(keyBuffer)).containsExactly(prefixValue, secondTarget);
	}

	private void patchSeekTail(ByteBuffer keyBuffer, int prefixLength, long target) {
		keyBuffer.limit(keyBuffer.capacity());
		keyBuffer.position(prefixLength);
		Varint.writeUnsigned(keyBuffer, target);
		keyBuffer.limit(keyBuffer.position());
		keyBuffer.position(0);
	}

	private long[] readPatchedPair(ByteBuffer keyBuffer) {
		ByteBuffer key = keyBuffer.duplicate();
		key.position(0);
		return new long[] {
				Varint.readUnsigned(key),
				Varint.readUnsigned(key)
		};
	}

	private int countMatches(String source, String regex) {
		int count = 0;
		Matcher matcher = Pattern.compile(regex).matcher(source);
		while (matcher.find()) {
			count++;
		}
		return count;
	}

	@SuppressWarnings("unchecked")
	private List<String> compiledFactoryClassNames(LmdbLftjCodegenCache cache) throws Exception {
		Field entriesField = LmdbLftjCodegenCache.class.getDeclaredField("entries");
		entriesField.setAccessible(true);
		Map<String, LmdbLftjCodegenCache.CacheEntry> entries = (LinkedHashMap<String, LmdbLftjCodegenCache.CacheEntry>) entriesField
				.get(cache);
		List<String> names = new ArrayList<>();
		for (LmdbLftjCodegenCache.CacheEntry entry : entries.values()) {
			if (entry.compiled()) {
				names.add(entry.factory().getClass().getName());
			}
		}
		return names;
	}

	@SuppressWarnings("unchecked")
	private List<String> cacheEntryDescriptions(LmdbLftjCodegenCache cache) throws Exception {
		Field entriesField = LmdbLftjCodegenCache.class.getDeclaredField("entries");
		entriesField.setAccessible(true);
		Map<String, LmdbLftjCodegenCache.CacheEntry> entries = (LinkedHashMap<String, LmdbLftjCodegenCache.CacheEntry>) entriesField
				.get(cache);
		List<String> descriptions = new ArrayList<>();
		for (Map.Entry<String, LmdbLftjCodegenCache.CacheEntry> entry : entries.entrySet()) {
			LmdbLftjCodegenCache.CacheEntry cacheEntry = entry.getValue();
			descriptions.add(entry.getKey() + "="
					+ (cacheEntry.compiled() ? cacheEntry.factory().getClass().getName()
							: cacheEntry.failureMessage()));
		}
		return descriptions;
	}

	@SuppressWarnings("unchecked")
	private List<String> preparedPlanDescriptions(LmdbLftjPreparedPlanCache cache) throws Exception {
		Field entriesField = LmdbLftjPreparedPlanCache.class.getDeclaredField("entries");
		entriesField.setAccessible(true);
		Map<String, LmdbLftjPlanner.PlanningResult> entries = (LinkedHashMap<String, LmdbLftjPlanner.PlanningResult>) entriesField
				.get(cache);
		List<String> descriptions = new ArrayList<>();
		for (Map.Entry<String, LmdbLftjPlanner.PlanningResult> entry : entries.entrySet()) {
			LmdbLftjPlanner.PlanningResult result = entry.getValue();
			descriptions.add(entry.getKey() + "=" + (result.planned() ? result.plan().fallbackExpr().getSignature()
					: result.rejectionReason()));
		}
		return descriptions;
	}

	private String foafCycleQuery(int size) {
		StringBuilder builder = new StringBuilder();
		builder.append("PREFIX foaf: <http://xmlns.com/foaf/0.1/>\n");
		builder.append("SELECT * WHERE {\n");
		for (int i = 0; i < size; i++) {
			builder.append("  ?")
					.append((char) ('a' + i))
					.append(" foaf:knows ?")
					.append((char) ('a' + ((i + 1) % size)))
					.append(" .\n");
		}
		builder.append("  FILTER (");
		boolean first = true;
		for (int i = 0; i < size; i++) {
			for (int j = i + 1; j < size; j++) {
				if (!first) {
					builder.append(" && ");
				}
				builder.append("?").append((char) ('a' + i)).append(" != ?").append((char) ('a' + j));
				first = false;
			}
		}
		builder.append(")\n");
		builder.append("}\n");
		return builder.toString();
	}

	private LmdbLftjPlan syntheticAliasedPlan() {
		LmdbLftjPlan basePlan = LmdbLftjSyntheticScenario.createPlan();
		return new LmdbLftjPlan(basePlan.fallbackExpr().clone(), Set.of("x", "y", "z"), Set.of("x", "y", "z"),
				basePlan.variableOrder(), basePlan.patternPlans(),
				List.of(
						new LmdbLftjPlan.OutputBinding("x", "a"),
						new LmdbLftjPlan.OutputBinding("y", "b"),
						new LmdbLftjPlan.OutputBinding("z", "c")),
				List.of(
						new LmdbLftjPlan.InequalityConstraint("a", "b"),
						new LmdbLftjPlan.InequalityConstraint("a", "c"),
						new LmdbLftjPlan.InequalityConstraint("b", "c")));
	}

	private LmdbLftjPlan syntheticDuplicateAliasedPlan() {
		LmdbLftjPlan basePlan = LmdbLftjSyntheticScenario.createPlan();
		return new LmdbLftjPlan(basePlan.fallbackExpr().clone(), Set.of("x", "x2", "z"), Set.of("x", "x2", "z"),
				basePlan.variableOrder(), basePlan.patternPlans(),
				List.of(
						new LmdbLftjPlan.OutputBinding("z", "c"),
						new LmdbLftjPlan.OutputBinding("x", "a"),
						new LmdbLftjPlan.OutputBinding("x2", "a")),
				List.of(
						new LmdbLftjPlan.InequalityConstraint("a", "b"),
						new LmdbLftjPlan.InequalityConstraint("a", "c"),
						new LmdbLftjPlan.InequalityConstraint("b", "c")));
	}

	private String foafCycleAliasQuery(int size) {
		StringBuilder builder = new StringBuilder();
		builder.append("PREFIX foaf: <http://xmlns.com/foaf/0.1/>\n");
		builder.append("SELECT ");
		for (int i = 0; i < size; i++) {
			if (i > 0) {
				builder.append(' ');
			}
			char variable = (char) ('a' + i);
			char alias = (char) ('x' + i);
			builder.append("(?").append(variable).append(" AS ?").append(alias).append(')');
		}
		builder.append(" WHERE {\n");
		for (int i = 0; i < size; i++) {
			builder.append("  ?")
					.append((char) ('a' + i))
					.append(" foaf:knows ?")
					.append((char) ('a' + ((i + 1) % size)))
					.append(" .\n");
		}
		builder.append("  FILTER (");
		boolean first = true;
		for (int i = 0; i < size; i++) {
			for (int j = i + 1; j < size; j++) {
				if (!first) {
					builder.append(" && ");
				}
				builder.append("?").append((char) ('a' + i)).append(" != ?").append((char) ('a' + j));
				first = false;
			}
		}
		builder.append(")\n");
		builder.append("}\n");
		return builder.toString();
	}

	private String foafCycleAliasQueryWithResidualFilter() {
		return "PREFIX foaf: <http://xmlns.com/foaf/0.1/>\n"
				+ "SELECT (?a AS ?x) (?b AS ?y) (?c AS ?z) WHERE {\n"
				+ "  ?a foaf:knows ?b .\n"
				+ "  ?b foaf:knows ?c .\n"
				+ "  ?c foaf:knows ?a .\n"
				+ "  FILTER (?a != ?b && ?a != ?c && ?b != ?c && STRSTARTS(STR(?a), \"urn:person:1\"))\n"
				+ "}\n";
	}

	private List<String> executeQueryRows(SailRepository repository, String query) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			List<String> rows = new ArrayList<>();
			try (var result = connection.prepareTupleQuery(query).evaluate()) {
				result.forEach(bindingSet -> rows.add(bindingSetKey(bindingSet)));
			}
			rows.sort(String::compareTo);
			return rows;
		}
	}

	private String bindingSetKey(BindingSet bindingSet) {
		List<String> names = new ArrayList<>(bindingSet.getBindingNames());
		names.sort(String::compareTo);
		StringBuilder builder = new StringBuilder();
		for (int i = 0; i < names.size(); i++) {
			if (i > 0) {
				builder.append('|');
			}
			String name = names.get(i);
			builder.append(name).append('=').append(bindingSet.getValue(name).stringValue());
		}
		return builder.toString();
	}

	private List<String> difference(List<String> left, List<String> right) {
		List<String> difference = new ArrayList<>(left);
		difference.removeAll(right);
		return difference;
	}

	private List<String> executeCompiledPlanRows(FullCodegenFixture fixture, LmdbLftjCodegenCompiler compiler,
			String query) throws Exception {
		try (SailRepositoryConnection connection = fixture.repository.getConnection()) {
			connection.prepareTupleQuery(query).explain(Explanation.Level.Optimized);
		}

		LmdbLftjPlan plan = preparedPlan(fixture.store).copy();
		LmdbLftjExecutionShape shape = new LmdbLftjExecutionShape(plan);
		LmdbQueryAccess queryAccess = fixture.connection.benchmarkQueryAccess(false);
		LmdbLftjBindingState state = new LmdbLftjBindingState(plan, EmptyBindingSet.getInstance(), queryAccess);
		assertThat(state.initialize()).isTrue();
		state.attachTxn(queryAccess.acquireReadTxn());
		QueryEvaluationContext context = new QueryEvaluationContext.Minimal((Dataset) null);
		LmdbCompiledLftjFactory factory = compiler.compile(plan, shape, false);
		try (CloseableIteration<BindingSet> iteration = factory.create(plan, shape, state, context, queryAccess,
				new LmdbLftjMetrics())) {
			List<String> rows = new ArrayList<>();
			while (iteration.hasNext()) {
				rows.add(bindingSetKey(iteration.next()));
			}
			rows.sort(String::compareTo);
			return rows;
		}
	}

	private LmdbLftjPlan optimizedPlan(String query, LmdbQueryAccess queryAccess) throws Exception {
		TupleExpr tupleExpr = parsedQueryRoot(query);
		LmdbLftjOptimizer optimizer = new LmdbLftjOptimizer(
				new LmdbLftjTripleSource(new EmptyTripleSource(), queryAccess));
		optimizer.optimize(tupleExpr, (Dataset) null, EmptyBindingSet.getInstance());
		LmdbLftjTupleExpr lftj = findNode(tupleExpr, LmdbLftjTupleExpr.class);
		assertThat(lftj).isNotNull();
		return lftj.plan().copy();
	}

	private TupleExpr parsedQueryRoot(String query) throws Exception {
		ParsedTupleQuery parsed = QueryParserUtil.parseTupleQuery(QueryLanguage.SPARQL, query, null);
		TupleExpr tupleExpr = parsed.getTupleExpr().clone();
		if (!(tupleExpr instanceof QueryRoot)) {
			tupleExpr = new QueryRoot(tupleExpr);
		}
		return tupleExpr;
	}

	private String sourceForPlan(LmdbLftjPlan plan, LmdbQueryAccess queryAccess, LmdbLftjCodegenCompiler compiler)
			throws Exception {
		LmdbLftjExecutionShape shape = new LmdbLftjExecutionShape(plan);
		Method sourceFor = findMethod(compiler.getClass(), "sourceFor", LmdbLftjPlan.class,
				LmdbLftjExecutionShape.class,
				boolean.class, LmdbQueryAccess.class);
		if (sourceFor != null) {
			return (String) sourceFor.invoke(compiler, plan, shape, false, queryAccess);
		}
		return compiler.sourceFor(plan, shape, false);
	}

	@SuppressWarnings("unchecked")
	private String sourceForPreparedPlan(LmdbBenchmarkStore store, LmdbLftjCodegenCompiler compiler) throws Exception {
		LmdbLftjPlan plan = preparedPlan(store);
		LmdbLftjExecutionShape shape = new LmdbLftjExecutionShape(plan);
		Path dump = Files.createTempFile("lmdb-lftj-generated-", ".java");
		compiler.dumpSourceFor(dump, plan, shape, false);
		return Files.readString(dump);
	}

	@SuppressWarnings("unchecked")
	private LmdbLftjPlan preparedPlan(LmdbBenchmarkStore store) throws Exception {
		Field entriesField = LmdbLftjPreparedPlanCache.class.getDeclaredField("entries");
		entriesField.setAccessible(true);
		Map<String, LmdbLftjPlanner.PlanningResult> entries = (LinkedHashMap<String, LmdbLftjPlanner.PlanningResult>) entriesField
				.get(store.preparedPlanCache());
		return entries.values()
				.stream()
				.filter(LmdbLftjPlanner.PlanningResult::planned)
				.map(LmdbLftjPlanner.PlanningResult::plan)
				.findFirst()
				.orElseThrow();
	}

	private Method findMethod(Class<?> type, String name, Class<?>... parameterTypes) {
		Class<?> current = type;
		while (current != null) {
			try {
				Method method = current.getDeclaredMethod(name, parameterTypes);
				method.setAccessible(true);
				return method;
			} catch (NoSuchMethodException e) {
				current = current.getSuperclass();
			}
		}
		return null;
	}

	private <T extends QueryModelNode> T findNode(TupleExpr tupleExpr, Class<T> type) {
		QueryModelNode[] result = new QueryModelNode[1];
		tupleExpr.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			protected void meetNode(QueryModelNode node) {
				if (result[0] == null && type.isInstance(node)) {
					result[0] = node;
				}
				super.meetNode(node);
			}
		});
		return type.cast(result[0]);
	}

	private Object readField(Object target, String name) throws Exception {
		Field field = target.getClass().getDeclaredField(name);
		field.setAccessible(true);
		return field.get(target);
	}

	private boolean isInitializedLmdbValue(Value value) throws Exception {
		Field field = value.getClass().getDeclaredField("initialized");
		field.setAccessible(true);
		return field.getBoolean(value);
	}

