	private static final class CachingQueryAccess extends LmdbLftjSyntheticScenario.TestQueryAccess {
		private final Map<String, LmdbLftjCodegenCache.CacheEntry> compiledPlans = new HashMap<>();
		private final LmdbLftjCodegenCompiler compiler;

		private CachingQueryAccess(LmdbLftjCodegenCompiler compiler) {
			this(false, compiler);
		}

		private CachingQueryAccess(boolean duplicateContexts, LmdbLftjCodegenCompiler compiler) {
			super(duplicateContexts);
			this.compiler = compiler;
		}

		@Override
		public LmdbLftjCodegenCache.CacheEntry cachedCompiledPlan(String executionKey) {
			return compiledPlans.get(executionKey);
		}

		@Override
		public void cacheCompiledPlanSuccess(String executionKey, LmdbCompiledLftjFactory factory) {
			compiledPlans.put(executionKey, LmdbLftjCodegenCache.CacheEntry.success(factory));
		}

		@Override
		public void cacheCompiledPlanFailure(String executionKey, String message) {
			compiledPlans.put(executionKey, LmdbLftjCodegenCache.CacheEntry.failure(message));
		}

		@Override
		public LmdbLftjCodegenCompiler codegenCompiler() {
			return compiler;
		}

		private LmdbLftjCodegenCache.CacheEntry cachedEntry(String executionKey) {
			return compiledPlans.get(executionKey);
		}
	}

	private static class CountingCompiler extends LmdbLftjCodegenCompiler {
		private int compileCalls;
		private RuntimeException failure;

		@Override
		LmdbCompiledLftjFactory compile(LmdbLftjPlan plan, LmdbLftjExecutionShape shape) {
			compileCalls++;
			try {
				return super.compile(plan, shape);
			} catch (RuntimeException e) {
				failure = e;
				throw e;
			}
		}

		private String failureDescription() {
			if (failure == null) {
				return "expected compiled factory cache entry";
			}
			Throwable cause = failure.getCause();
			return cause == null ? failure.toString() : failure + " | cause=" + cause;
		}
	}

	private static final class FailingCompiler extends LmdbLftjCodegenCompiler {
		private int compileCalls;

		@Override
		LmdbCompiledLftjFactory compile(LmdbLftjPlan plan, LmdbLftjExecutionShape shape) {
			compileCalls++;
			throw new IllegalArgumentException("forced failure");
		}
	}

	private static final class FullCodegenFixture implements AutoCloseable {
		private final SailRepository repository;
		private final LmdbBenchmarkStore store;
		private final LmdbBenchmarkStore.BenchmarkStoreConnection connection;
		private final File dataDir;

		private FullCodegenFixture() throws IOException {
			this(4, true, true, LmdbLftjFullCodegenCompiler.INSTANCE);
		}

		private FullCodegenFixture(int personCount, LmdbLftjCodegenCompiler compiler) throws IOException {
			this(personCount, true, true, compiler);
		}

		private FullCodegenFixture(int personCount, boolean lftjEnabled, boolean lftjCodegenEnabled,
				LmdbLftjCodegenCompiler compiler) throws IOException {
			dataDir = Files.createTempDirectory("rdf4j-lmdb-full-codegen-test").toFile();
			LmdbStoreConfig config = new LmdbStoreConfig("spoc,sopc,psoc,posc,ospc,opsc");
			config.setLftjEnabled(lftjEnabled);
			config.setLftjCodegenEnabled(lftjCodegenEnabled);
			config.setForceSync(false);
			config.setValueDBSize(64L * 1024 * 1024);
			config.setTripleDBSize(config.getValueDBSize());
			store = new LmdbBenchmarkStore(dataDir, config, compiler);
			repository = new SailRepository(store);
			repository.init();
			populate(repository, personCount);
			connection = (LmdbBenchmarkStore.BenchmarkStoreConnection) store.getConnection();
		}

		@Override
		public void close() throws Exception {
			try {
				connection.close();
			} finally {
				repository.shutDown();
				FileUtils.deleteDirectory(dataDir);
			}
		}

		private static void populate(SailRepository repository, int personCount) {
			try (SailRepositoryConnection connection = repository.getConnection()) {
				for (long subject = 1; subject <= personCount; subject++) {
					for (long object = 1; object <= personCount; object++) {
						if (subject != object) {
							connection.add(person(subject), FOAF.KNOWS, person(object));
						}
					}
				}
			}
		}

		private static org.eclipse.rdf4j.model.IRI person(long id) {
			return LmdbLftjSyntheticScenario.VF.createIRI("urn:person:" + id);
		}
	}

